css_template:
#{{ID}} .modern-lt-container {
padding: 0;
font-family: '{{FONT_FAMILY}}', sans-serif;
line-height: {{LINE_HEIGHT}};
}
#{{ID}} .modern-plate {
background: {{PRIMARY_BG}};
padding: 24px 48px;
border-radius: 12px;
color: white;
display: inline-block;
box-shadow: {{BOX_SHADOW}};
opacity: 0;
transform: {{ANIMATION_IN_TRANSFORM}};
transition: all {{ANIMATION_DURATION}}s {{ANIMATION_EASE}};
border: 1px solid rgba(255,255,255,0.1);
backdrop-filter: blur(10px);
}
#{{ID}} .modern-title {
margin: 0;
font-size: {{TITLE_SIZE}}px;
font-weight: {{TITLE_WEIGHT}};
text-transform: {{TITLE_TRANSFORM}};
letter-spacing: 1px;
text-shadow: 2px 2px 4px rgba(0,0,0,0.3);
}
#{{ID}} .modern-plate {
position: relative;
overflow: hidden;
}
#{{ID}} .modern-plate::after {
content: '';
position: absolute;
top: 0;
left: -100%;
width: 50%;
height: 100%;
background: linear-gradient(to right, rgba(255,255,255,0) 0%, rgba(255,255,255,0.3) 50%, rgba(255,255,255,0) 100%);
transform: skewX(-20deg);
animation: shine 6s infinite;
}
@keyframes shine {
0% { left: -100%; }
20% { left: 200%; }
100% { left: 200%; }
}

js_template:
(() => { const root = document.getElementById("{{ID}}"); const container = root.querySelector('.modern-plate'); root.__slt_show = () => { const tl = GSAPFX.standardIn(container, {{{ANIMATION_IN_JSON}}}); const textTl = GSAPFX.applyTextEffect(root, {{{TEXT_ANIM_JSON}}}); if (textTl) {
            if ({{{TEXT_ANIM_SYNC}}}) {
                tl.add(textTl, ">-0.1");
            } else {
                tl.add(textTl, 0);
            }
        } return tl; }; root.__slt_hide = () => { const textTl = GSAPFX.applyTextOutEffect(root, {{{TEXT_ANIM_OUT_JSON}}}); const tl = GSAPFX.standardOut(container, {{{ANIMATION_OUT_JSON}}}); if (textTl) {
            if ({{{TEXT_ANIM_OUT_SYNC}}}) {
                const combined = gsap.timeline();
                combined.add(textTl);
                combined.add(tl, ">-0.1");
                return combined;
            } else {
                tl.add(textTl, 0);
            }
        } return tl; }; })();
